sql:
SELECT AVG(humidity) AS average_humidity
FROM humidity_records
WHERE city_id = 1;

SELECT humidity
FROM humidity_records
WHERE quality = 'high';

SELECT MAX(temp_max) AS max_temperature
FROM weather_reports
WHERE city_id = 1;

SELECT COUNT(*) AS total_accesses
FROM weather_access_logs
WHERE user_type = 'data_analyst' AND access_date = '2023-10-01 12:00:00';

SELECT city_name 
FROM cities 
ORDER BY city_name;

